esqlQuery.esql:
FROM metrics-haproxyreceiver.otel-*
// Scope to backend aggregates (not frontends or individual servers)
| WHERE haproxy.service_name == "BACKEND"
// Exclude stats backend — it has no upstream servers by design
| WHERE haproxy.proxy_name != "stats"
// Aggregate minimum active count per backend over the time window
| STATS min_active = MIN(haproxy.active) BY haproxy.proxy_name, haproxy.addr
// Alert when any backend has zero active servers
| WHERE min_active < 1
| EVAL alert_key = CONCAT(TO_STRING(haproxy.proxy_name), "::", COALESCE(TO_STRING(haproxy.addr), ""))
| LIMIT 50
